def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            base_val = np.sin(ratio * np.pi * 20) + np.cos(capacity / 10)
            for k in range(1, 15):
                val = (base_val + k**1.8) / (k + ratio * 2)
                if k % 4 == 1:
                    val *= np.exp(-ratio * k)
                else:
                    val /= (1 + ratio * k)
                score += val
            if capacity % 4 == 2 and int(item) % 2 == 0:
                score *= 0.75
            if score < 3:
                score += 5 * ratio
        elif 0.05 <= ratio < 0.15:
            acc_mul = 1
            for n in range(2, int(capacity) + 3):
                acc_mul *= (np.log1p(ratio + n) / (n * 0.75))
                if acc_mul > 5e5:
                    acc_mul = np.sqrt(acc_mul)
                    break
            score += np.tanh(acc_mul * ratio) * 10
            if int(capacity) % 5 == 0 or int(item * 3) % 7 == 0:
                score -= 2.7
            for x in range(1, 8):
                score += ((ratio * x**3) % 0.7) * (x ** 1.4)
        elif 0.15 <= ratio <= 0.4:
            for m in range(1, 10):
                inc = ((ratio ** (m + 1)) * (m ** 3)) / ((m + 3) ** 1.1)
                if m % 2 == 0:
                    inc *= 1.1
                else:
                    inc *= 0.9
                score += inc
            gap = capacity - item
            if gap < 1:
                score += 12 * gap
            elif gap < 6:
                score += 5 - gap
            else:
                score -= gap * 0.8
            if int(capacity * ratio) % 9 == 0:
                score *= 1.15
            if score > 20:
                score /= 4
        elif 0.4 < ratio <= 0.7:
            penalty_sum = 0
            for p in range(1, 12):
                pow_val = ((ratio - 0.4) ** p)
                penalty_sum += pow_val * (p ** 2.1) * np.sin(p * ratio * 3)
                if penalty_sum > 80:
                    penalty_sum = np.cbrt(penalty_sum)
                    break
            score = penalty_sum * 8
            if capacity < item * 1.1:
                score += 12
            if (int(capacity) % 8 == 0) and (int(item * 7) % 6 == 0):
                score -= 8
            if score < -7:
                score = abs(score) * 0.4 + 3
            if score > 110:
                score = 110
        elif 0.7 < ratio <= 1.1:
            ext_penalty = 0
            diff = ratio - 0.7
            for q in range(1, 13):
                ext_penalty += (diff ** q) * (q ** 2.3) / (q + 0.5) * np.cos(q * diff)
                if ext_penalty > 60:
                    ext_penalty = np.log1p(ext_penalty) * 2
                    break
            score = ext_penalty * 15
            if capacity < item * 1.25:
                score += 20
            if (int(capacity * 4) % 9 == 0) and (int(item * 11) % 8 == 0):
                score -= 9
            for z in range(1, 7):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1300:
                score = 1300
        elif 1.1 < ratio <= 1.8:
            super_penalty = 0
            diff = ratio - 1.1
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.5) * np.sin(r * diff)
                if term > 15000:
                    term = term ** 0.4
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.1:
                score += 35
            if (int(capacity * 10) % 6 == 0) and (int(item * 13) % 7 == 0):
                score -= 15
            for w in range(3, 8):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 7
            if score > 2200:
                score = 2200
        else:
            ultimate_penalty = 0
            diff = ratio - 1.8
            for s in range(1, 18):
                term = ((diff) ** s) * (s ** 4) * np.tanh(diff * s)
                if term > 20000:
                    term = np.sqrt(term)
                ultimate_penalty += term
            score = ultimate_penalty * 40
            if capacity < item * 3:
                score += 45
            if (int(capacity * 14) % 5 == 0) and (int(item * 19) % 9 == 0):
                score -= 20
            for v in range(2, 10):
                score += ((diff / v) % 1) * (v * 3)
            if score < 0:
                score = abs(score) * 0.8 + 9
            if score > 3000:
                score = 3000
        if capacity > 250:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 3:
            score *= 2.8
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 1
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        mean_val = np.mean(finite_priorities)
        fill_value = (np.max(finite_priorities) * (20 + top_count) - median_val) / (1 + mean_val % 3)
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else fill_value / 2
    return priorities
